        """Look at current token without consuming it."""
        return tokens[pos[0]] if pos[0] < len(tokens) else None

    def consume():
        """Consume and return current token."""
        token = tokens[pos[0]]
        pos[0] += 1
        return token

    def parse_expression():
        """Parse expression: term (('+' | '-') term)*"""
        node = parse_term()
        while peek() in ('+', '-'):
            op = consume()
            right = parse_term()
            node = ASTNode('binop', op=op, left=node, right=right)
        return node

    def parse_term():
        """Parse term: unary (('*' | '/') unary)*"""
        node = parse_unary()
        while peek() in ('*', '/'):
            op = consume()
            right = parse_unary()
            node = ASTNode('binop', op=op, left=node, right=right)
        return node

    def parse_unary():
        """Parse unary: '-' unary | primary"""
